 91→	}
 92→	RespondJSON(w, r, http.StatusOK, releases)
 93→}
 94→
 95→// Delete handles DELETE /semantic-releases/{id} — deletes a single semantic release.
 96→func (h *SemanticReleasesHandler) Delete(w http.ResponseWriter, r *http.Request) {
 97→	id := r.PathValue("id")
 98→	if id == "" {
 99→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Semantic release ID is required")
100→		return
101→	}
102→	if err := h.store.DeleteSemanticRelease(r.Context(), id); err != nil {
103→		RespondError(w, r, http.StatusNotFound, "not_found", "Semantic release not found")
104→		return
105→	}
106→	w.WriteHeader(http.StatusNoContent)
107→}
