  4→import { useState } from "react";
  5→import useSWR from "swr";
  6→import { system } from "@/lib/api/client";
  7→import {
  8→  BarChart,
  9→  Bar,
 10→  XAxis,
 11→  YAxis,
 12→  Tooltip,
 13→  ResponsiveContainer,
 14→  CartesianGrid,
 15→} from "recharts";
 16→import type { TrendBucket } from "@/lib/api/types";
 17→import { useTranslation } from "@/lib/i18n/context";
 18→
 19→type Granularity = "daily" | "weekly" | "monthly";
 20→
 21→const RANGE_OPTIONS = [
 22→  { label: "7d", days: 7, granularity: "daily" as Granularity },
 23→  { label: "30d", days: 30, granularity: "daily" as Granularity },
 24→  { label: "90d", days: 90, granularity: "weekly" as Granularity },
 25→  { label: "1y", days: 365, granularity: "monthly" as Granularity },
 26→];
 27→
 28→function formatPeriod(period: string, granularity: Granularity): string {
 29→  const d = new Date(period + "T00:00:00");
 30→  switch (granularity) {
 31→    case "daily":
 32→      return d.toLocaleDateString("en-US", { month: "short", day: "numeric" });
 33→    case "weekly":
 34→      return d.toLocaleDateString("en-US", { month: "short", day: "numeric" });
 35→    case "monthly":
 36→      return d.toLocaleDateString("en-US", { month: "short", year: "2-digit" });
 37→  }
 38→}
 39→
 40→export function ReleaseTrendChart() {
 41→  const [rangeIdx, setRangeIdx] = useState(0);
 42→  const range = RANGE_OPTIONS[rangeIdx];
 43→  const { t } = useTranslation();
 44→
 45→  const { data, isLoading } = useSWR(
 46→    `trend-${range.granularity}-${range.days}`,
 47→    () => system.trend(range.granularity, range.days),
 48→    { refreshInterval: 30_000 }
 49→  );
 50→
 51→  const buckets: TrendBucket[] = data?.data?.buckets ?? [];
 52→
 53→  const chartData = buckets.map((b) => ({
 54→    ...b,
 55→    label: formatPeriod(b.period, range.granularity),
 56→  }));
 57→
 58→  return (
 59→    <div
 60→      className="flex flex-col rounded-lg bg-surface px-5 py-4 border border-border"
 61→      style={{ height: "336px" }}
 62→    >
 63→      <div className="flex items-center justify-between">
 64→        <p
 65→          className="text-xs uppercase tracking-[0.08em] text-text-secondary"
 66→          style={{
 67→            fontFamily: "var(--font-dm-sans)",
 68→            fontSize: "12px",
 69→          }}
 70→        >
 71→          {t("dashboard.trend.title")}
 72→        </p>
 73→        <div className="flex gap-1">
 74→          {RANGE_OPTIONS.map((opt, idx) => (
 75→            <button
 76→              key={opt.label}
 77→              onClick={() => setRangeIdx(idx)}
 78→              className="rounded px-2 py-0.5 text-xs font-medium transition-colors"
 79→              style={{
 80→                fontFamily: "var(--font-dm-sans)",
 81→                fontSize: "11px",
 82→                backgroundColor:
 83→                  rangeIdx === idx ? "var(--foreground)" : "transparent",
 84→                color: rangeIdx === idx ? "var(--surface)" : "var(--text-secondary)",
 85→                border:
 86→                  rangeIdx === idx
 87→                    ? "1px solid var(--foreground)"
 88→                    : "1px solid var(--border)",
 89→              }}
 90→            >
 91→              {opt.label}
 92→            </button>
 93→          ))}
 94→        </div>
 95→      </div>
 96→
 97→      <div className="relative mt-3 flex-1" style={{ minHeight: "100px" }}>
 98→        {isLoading ? (
 99→          <div
100→            className="flex h-full items-center justify-center text-text-secondary"
101→            style={{
102→              fontFamily: "var(--font-dm-sans)",
103→              fontSize: "13px",
104→            }}
105→          >
106→            {t("dashboard.loading")}
107→          </div>
108→        ) : chartData.length === 0 ? (
109→          <div
110→            className="flex h-full items-center justify-center text-text-muted"
111→            style={{
112→              fontFamily: "var(--font-dm-sans)",
113→              fontSize: "13px",
114→            }}
115→          >
116→            {t("dashboard.trend.noData")}
117→          </div>
118→        ) : (
119→          <div className="absolute inset-0">
120→            <ResponsiveContainer width="100%" height="100%">
121→              <BarChart
122→                data={chartData}
123→                margin={{ top: 4, right: 0, bottom: 0, left: -20 }}
124→                barGap={1}
125→                barCategoryGap="20%"
126→              >
127→                <CartesianGrid
128→                  strokeDasharray="3 3"
129→                  stroke="var(--border)"
130→                  vertical={false}
131→                />
132→                <XAxis
133→                  dataKey="label"
134→                  tick={{ fontSize: 10, fill: "var(--text-muted)" }}
135→                  tickLine={false}
136→                  axisLine={{ stroke: "var(--border)" }}
137→                  interval="preserveStartEnd"
138→                />
139→                <YAxis
140→                  tick={{ fontSize: 10, fill: "var(--text-muted)" }}
141→                  tickLine={false}
142→                  axisLine={false}
143→                  allowDecimals={false}
144→                />
145→                <Tooltip
146→                  contentStyle={{
147→                    fontFamily: "var(--font-dm-sans)",
148→                    fontSize: "12px",
149→                    borderRadius: "6px",
150→                    border: "1px solid var(--border)",
151→                    backgroundColor: "var(--surface)",
152→                    boxShadow: "0 2px 8px rgba(0,0,0,0.06)",
153→                  }}
154→                  labelStyle={{ fontWeight: 600, color: "var(--foreground)" }}
155→                  cursor={{ fill: "rgba(0,0,0,0.03)" }}
156→                />
157→                <Bar
158→                  dataKey="releases"
159→                  name={t("dashboard.trend.releases")}
160→                  fill="var(--beacon-accent)"
161→                  radius={[2, 2, 0, 0]}
162→                  maxBarSize={20}
163→                />
164→                <Bar
165→                  dataKey="semantic_releases"
166→                  name={t("dashboard.trend.semanticReleases")}
167→                  fill="#f4a261"
168→                  radius={[2, 2, 0, 0]}
169→                  maxBarSize={20}
170→                />
171→              </BarChart>
172→            </ResponsiveContainer>
173→          </div>
174→        )}
175→      </div>
176→    </div>
