 3→import (
 4→	"context"
 5→	"net/http"
 6→
 7→	"github.com/sentioxyz/changelogue/internal/models"
 8→)
 9→
10→// ReleasesStore defines the persistence operations for releases (read-only).
11→type ReleasesStore interface {
12→	ListAllReleases(ctx context.Context, page, perPage int, includeExcluded bool) ([]models.Release, int, error)
13→	ListReleasesBySource(ctx context.Context, sourceID string, page, perPage int, includeExcluded bool) ([]models.Release, int, error)
14→	ListReleasesByProject(ctx context.Context, projectID string, page, perPage int, includeExcluded bool) ([]models.Release, int, error)
15→	GetRelease(ctx context.Context, id string) (*models.Release, error)
16→}
17→
18→// ReleasesHandler implements HTTP handlers for the /releases resource.
19→type ReleasesHandler struct {
20→	store ReleasesStore
21→}
22→
23→// NewReleasesHandler returns a new ReleasesHandler.
24→func NewReleasesHandler(store ReleasesStore) *ReleasesHandler {
25→	return &ReleasesHandler{store: store}
26→}
27→
28→// List handles GET /releases — returns all releases across all projects.
29→func (h *ReleasesHandler) List(w http.ResponseWriter, r *http.Request) {
30→	page, perPage := ParsePagination(r)
31→	includeExcluded := r.URL.Query().Get("include_excluded") == "true"
32→	releases, total, err := h.store.ListAllReleases(r.Context(), page, perPage, includeExcluded)
33→	if err != nil {
34→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list releases")
35→		return
36→	}
37→	if releases == nil {
38→		releases = []models.Release{}
39→	}
40→	RespondList(w, r, http.StatusOK, releases, page, perPage, total)
41→}
42→
43→// ListBySource handles GET /sources/{id}/releases — returns releases for a specific source.
44→func (h *ReleasesHandler) ListBySource(w http.ResponseWriter, r *http.Request) {
45→	sourceID := r.PathValue("id")
46→	if sourceID == "" {
47→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Source ID is required")
48→		return
49→	}
50→	page, perPage := ParsePagination(r)
51→	includeExcluded := r.URL.Query().Get("include_excluded") == "true"
52→	releases, total, err := h.store.ListReleasesBySource(r.Context(), sourceID, page, perPage, includeExcluded)
53→	if err != nil {
54→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list releases")
55→		return
56→	}
57→	if releases == nil {
58→		releases = []models.Release{}
59→	}
60→	RespondList(w, r, http.StatusOK, releases, page, perPage, total)
61→}
62→
63→// ListByProject handles GET /projects/{projectId}/releases — returns releases for all sources in a project.
64→func (h *ReleasesHandler) ListByProject(w http.ResponseWriter, r *http.Request) {
65→	projectID := r.PathValue("projectId")
66→	if projectID == "" {
67→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Project ID is required")
68→		return
69→	}
70→	page, perPage := ParsePagination(r)
71→	includeExcluded := r.URL.Query().Get("include_excluded") == "true"
72→	releases, total, err := h.store.ListReleasesByProject(r.Context(), projectID, page, perPage, includeExcluded)
73→	if err != nil {
74→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list releases")
75→		return
76→	}
77→	if releases == nil {
78→		releases = []models.Release{}
79→	}
80→	RespondList(w, r, http.StatusOK, releases, page, perPage, total)
81→}
82→
83→// Get handles GET /releases/{id} — returns a single release.
84→func (h *ReleasesHandler) Get(w http.ResponseWriter, r *http.Request) {
85→	id := r.PathValue("id")
86→	if id == "" {
87→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Release ID is required")
88→		return
89→	}
90→	rel, err := h.store.GetRelease(r.Context(), id)
91→	if err != nil {
92→		RespondError(w, r, http.StatusNotFound, "not_found", "Release not found")
93→		return
94→	}
95→	RespondJSON(w, r, http.StatusOK, rel)
96→}
